/* Transformation Name ==>INS_LOAN ,Transformation Type ==>Target */

{{
	config(
		materialized='incremental',
		alias='LOAN',
		schema='',
		pre_hook ="",
		post_hook ="",
		incremental_strategy='append')
}}

With SS_SRC_PVMOut as (
	/* SubQuery from Source ==>SS_SRC_PVM */
Select 
LOANNUMBER,
ASISVALUE,
DUMMY
 from 
(SELECT LOANNUMBER, ASISVALUE, 1 as DUMMY FROM (SELECT PV1.LOANNUMBER, PV4.ASISVALUE FROM {{ source('DBO','TBL_PROPERTY') }} as PV1 INNER JOIN (SELECT PV2.PROPERTYID, PV2.ASISVALUE FROM {{ source('DBO','TBL_VALUATION') }} as PV2 INNER JOIN (SELECT PROPERTYID, MAX(VALUATIONDATE) as VALUATIONDATE FROM {{ source('DBO','TBL_VALUATION') }} GROUP BY PROPERTYID) PV3 ON PV2.PROPERTYID= PV3.PROPERTYID AND PV2.VALUATIONDATE= PV3.VALUATIONDATE) PV4 ON PV1.ID= PV4.PROPERTYID) PV)
 ),

SRC_SS_LSBKCAS00Out as (
	/* SubQuery from Source ==>SRC_SS_LSBKCAS00 */
Select 
LOAN_NBR,
BRND_NM,
CASE_STS_CD,
CASE_CLOSE_DT,
KEY1,
FILE_CHAP_CD
 from 
(SELECT LOAN_NBR, BRND_NM, FILE_CHAP_CD, CASE_STS_CD, CASE_CLOSE_DT, CAST(1 AS SMALLINT) as KEY1 FROM (SELECT CAST(BCLOANNBR AS VARCHAR(16)) as LOAN_NBR, CAST(LSLOAN00.LSBRAND AS VARCHAR(16)) as BRND_NM, CAST(BCCHPFILED AS VARCHAR(2)) as FILE_CHAP_CD, CAST(BCSTATUS AS CHAR(1)) as CASE_STS_CD, CASE WHEN BCCLOSEDT = 0 THEN NULL ELSE CAST(CAST(BCCLOSEDT AS VARCHAR(8)) AS DATE) END as CASE_CLOSE_DT, RANK() OVER(PARTITION BY BCLOANNBR,BCCASENBR ORDER BY LSBKCAS00.LOAD_DTTM DESC) as RNK FROM {{ source('ADMIN','LSBKCAS00') }} JOIN {{ source('ADMIN','LSLOAN00') }} ON LSLOAN00.LSLN_N= LSBKCAS00.BCLOANNBR WHERE COALESCE(BCCLOSEDT,0)= 0 AND LTRIM(RTRIM(BCSTATUS))  !=  'C') LSBKCAS00 WHERE RNK= 1)
 ),

SS_REF_ZIP_TO_FIPOut as (
	/* SubQuery from Source ==>SS_REF_ZIP_TO_FIP */
Select 
MSA_TXT,
ZIP_CODE
 from 
(SELECT CAST(MSA AS VARCHAR(255)) as MSA_TXT, CAST(LTRIM(RTRIM(ZIP_CODE)) AS VARCHAR(9)) as ZIP_CODE FROM {{ source('EXTNLDATAFILES','REF_ZIP_TO_FIP') }})
 ),

LOAN_NBR_CROSS_REFOut as (
	Select LOAN_KEY, 
		LOAN_NBR, 
		BRND_NM
 from 
{{ source ('LOAN_NBR_CROSS_REF','LOAN_NBR_CROSS_REF') }}
 ),

