LOAN_ACQ_METH_CD,
LOAN_AGE,
AMZ_TERM,
GRT_FEE,
LAST_ACTV_DT,
LAST_DUE_DT,
LSAMS_RFD_CD,
MTG_INSMT,
MTG_TYPE,
MTH_PAST_DUE,
NON_SFCNT_FUND_CHRG_AMT,
SRVC_FEE_AMT,
