NEG_AMZ_IND,
CNSMR_LOAN_FLG
 from 
(SELECT LOAN_KEY, SOR_CD, LOAN_TYPE_CD, LOAN_STS_CD, INVSTR_CD, POOL_ID, NOTE_PCT_RT as NOTE_RT_PCT, NOTE_AMT, UPB_AMT, ESCRW_ADVN_AMT, ESCRW_BAL_AMT, ESCRW_BAL_UNENCB_AMT, MTH_LATE_CHRG_AMT, LAST_PYMT_RCVD_DT as LAST_PYMT_RCV_DT, NXT_PYMT_DUE_DT, LOAN_MTR_DT, LAST_ESCRW_ANLS_DT, FRCLS_IND, BKPT_IND, ARM_IND, ESCRW_IND, REO_IND, HGHR_PRC_MTG_LOAN_IND, LATE_CHRG_CD, LATE_CHRG_GRACE_PRD_DAY_CNT, LATE_CHRG_PCT_RT as LATE_CHRG_RT_PCT, INT_MTH_CD as INT_METH_CD, BRND_NM, DSCHRG_BKPT_IND, PYMT_APPL_PLN_NBR, WSITE_ACCS_ALOW_IND as WEBSITE_ACCS_ALOW_IND, IVR_PYMT_ALOW_IND, PROD_CD, PRIN_PYMT_ALOW_IND, TXN_FEE_ELG_CD, LATE_CHRG_SRC_CD, TOT_ANUL_FEE_BILL_AMT as TOT_ANUL_FEE_BILLED_AMT, FHA_VA_CASE_NBR, FHA_CASE_ASGN_DT, MI_PREM_FNCE_IND_CD, MI_PREM_PCT_RT as MI_PREM_RT_PCT, INVSTR_LOAN_NBR, MI_IND, LIEN_PSTN, RMN_TERM, CURR_LTV, CURR_CLTV, ORGNL_CLTV as Orig_CLTV, PROD_CD_DESC, SECURITIZED_DT, CAST(ESCRW_ORGNL_PYMT as number(7,2)) as ESCRW_ORGNL_PYMT, PAPERLESS_STMT_IND, MIN_HZRD_RT_RQR, ESCRW_ADVN_BY_INVSTR, FRST_PYMT_DUE_DT, BLN_IND, INT_ONLY_IND, MSA_TXT, LOAN_ACQ_MTH_CD as LOAN_ACQ_METH_CD, LOAN_AGE, AMZ_TERM, GRT_FEE, LAST_ACTV_DT, LAST_DUE_DT, LSAMS_RFD_CD, MTG_INSMT, MTG_TYPE, MTH_PAST_DUE, NON_SFCNT_FUND_CHRG_AMT, SRVC_FEE_AMT, YR_TO_DT_WHLD, INT_ONLY_TERM, STOP_ADVN_FLG, TOT_ADVN_BAL_AMT, WI_TAX_OPT, FLOOD_INS_RQR_FLG, INVSTR_POOL_NBR, MI_PCT_CVR_AMT, LOAN_TYPE_IND, CAST(MIN_MERS_NBR AS CHAR(18)) as MIN_MERS_NBR, RGST_WITH_MERS_FLG, NEG_AMZ_IND, CNSMR_LOAN_FLG FROM {{ source('dbo','LOAN') }} as a WHERE A.LOAN_KEY= ORCHESTRATE.LOAN_KEY AND A.SOR_CD= ORCHESTRATE.SOR_CD)
 ),

SRC_SS_SRVDSROut as (
	/* SubQuery from Source ==>SRC_SS_SRVDSR */
Select 
LOAN_NBR,
BRND_NM,
LOAN_TYPE_CD,
LOAN_STS_CD,
INVSTR_CD,
POOL_ID,
NOTE_RT_PCT,
NOTE_AMT,
UPB_AMT,
ESCRW_ADVN_AMT,
ESCRW_BAL_AMT,
ESCRW_BAL_UNENCB_AMT,
MTH_LATE_CHRG_AMT,
LAST_PYMT_RCV_DT,
NXT_PYMT_DUE_DT,
LOAN_MTR_DT,
LAST_ESCRW_ANLS_DT,
ARM_IND,
ESCRW_IND,
HGHR_PRC_MTG_LOAN_IND,
LATE_CHRG_CD,
LATE_CHRG_GRACE_PRD_DAY_CNT,
LATE_CHRG_RT_PCT,
INT_METH_CD,
PYMT_APPL_PLN_NBR,
PROD_CD,
LATE_CHRG_SRC_CD,
TOT_ANUL_FEE_BILLED_AMT,
FHA_VA_CASE_NBR,
FHA_CASE_ASGN_DT,
MI_PREM_FNCE_IND_CD,
MI_PREM_RT_PCT,
INVSTR_LOAN_NBR,
MI_IND,
LIEN_PSTN,
RMN_TERM,
CURR_LTV,
CURR_CLTV,
Orig_CLTV,
PROD_CD_DESC,
SECURITIZED_DT,
ESCRW_ORGNL_PYMT,
PAPERLESS_STMT_IND,
MIN_HZRD_RT_RQR,
ESCRW_ADVN_BY_INVSTR,
FRST_PYMT_DUE_DT,
BLN_IND,
INT_ONLY_IND,
MSA_TXT,
LOAN_ACQ_METH_CD,
LOAN_AGE,
AMZ_TERM,
GRT_FEE,
LAST_ACTV_DT,
LAST_DUE_DT,
LSAMS_RFD_CD,
MTG_INSMT,
MTG_TYPE,
MTH_PAST_DUE,
NON_SFCNT_FUND_CHRG_AMT,
SRVC_FEE_AMT,
YR_TO_DT_WHLD,
INT_ONLY_TERM,
STOP_ADVN_FLG,
TOT_ADVN_BAL_AMT,
SMM030,
SMM040,
SMM050,
SMR110,
SMR070,
SMM090,
SMA300,
WI_TAX_OPT,
FLOOD_INS_RQR_FLG,
INVSTR_POOL_NBR,
MI_PCT_CVR_AMT,
MIN_MERS_NBR,
RGST_WITH_MERS_FLG,
AUD_CRE_BY_NM,
AUD_CRE_DTTM,
AUD_UPD_BY_NM,
AUD_UPD_DTTM,
TRUNCATE_FLAG,
LOAN_TYPE_IND,
PROP_ZIP,
NEG_AMZ_IND,
LAST_APPR_VAL,
ORIG_APPR_VAL,
SAL_PR,
CNSMR_LOAN_FLG
 from 
(WITH CNSMR_LOAN_CHK as ( SELECT distinct SUBSTRING(TEXT,number,2) as CNSMR_LOAN_CD FROM MASTER.dbo.SPT_VALUES as S INNER JOIN {{ source('ADMIN','SRVFACT') }} ON KEY= 'CONSUMLT' WHERE NUMBER BETWEEN 1 AND LENGTH(TEXT) AND NUMBER % 2 != 0) SELECT distinct CAST(U_LOAN_NUM AS VARCHAR(16)) as LOAN_NBR, CAST(LTRIM(RTRIM(LSLOAN00.LSBRAND)) AS VARCHAR(16)) as BRND_NM, CAST(SML010 AS VARCHAR(16)) as LOAN_TYPE_CD, CAST(SMM090 AS VARCHAR(16)) as LOAN_STS_CD, CAST(SMR070 AS VARCHAR(16)) as INVSTR_CD, CAST(SMR110 AS VARCHAR(16)) as POOL_ID, CAST(SML060 * 100 AS NUMERIC(6,3)) as NOTE_RT_PCT, CAST(SML040 AS NUMERIC(19,4)) as NOTE_AMT, CAST(SMA240 AS NUMERIC(19,4)) as UPB_AMT, COALESCE(CAST(SME050 AS NUMERIC(19,4)),0.00) as ESCRW_ADVN_AMT, COALESCE(CAST(SME040 AS NUMERIC(19,4)),0.00) as ESCRW_BAL_AMT, COALESCE(CAST(SME020 AS NUMERIC(19,4)),0.00) as ESCRW_BAL_UNENCB_AMT, CAST(SMA180 AS NUMERIC(19,4)) as MTH_LATE_CHRG_AMT, CAST(CASE WHEN(SMA151 IS NULL OR SMA152 IS NULL OR SMA153 IS NULL OR SMA151 = 0 OR SMA152 = 0 OR SMA153 = 0) THEN NULL WHEN(SMA151 >= 1 AND SMA151 <= 12) AND(SMA152 >= 1 AND SMA152 <= 31) AND(SMA153 >= 1753) THEN CAST(SMA153 AS VARCHAR(4)) || '-' || RIGHT('00' || CAST(SMA151 AS VARCHAR(2)),2) || '-' || RIGHT('00' || CAST(SMA152 AS VARCHAR(2)),2) ELSE NULL END AS VARCHAR(10)) as LAST_PYMT_RCV_DT, CAST(CASE WHEN(SMA131 IS NULL OR SMA132 IS NULL OR SMA133 IS NULL OR SMA131 = 0 OR SMA132 = 0 OR SMA133 = 0) THEN NULL WHEN(SMA131 >= 1 AND SMA131 <= 12) AND(SMA132 >= 1 AND SMA132 <= 31) AND(SMA133 >= 1753) THEN CAST(SMA133 AS VARCHAR(4)) || '-' || RIGHT('00' || CAST(SMA131 AS VARCHAR(2)),2) || '-' || RIGHT('00' || CAST(SMA132 AS VARCHAR(2)),2) ELSE NULL END AS VARCHAR(10)) as NXT_PYMT_DUE_DT, CAST(CASE WHEN(SML291 IS NULL OR SML292 IS NULL OR SML293 IS NULL OR SML291 = 0 OR SML292 = 0 OR SML293 = 0) THEN NULL WHEN(SML291 >= 1 AND SML291 <= 12) AND(SML292 >= 1 AND SML292 <= 31) AND(SML293 >= 1753) THEN CAST(SML293 AS VARCHAR(4)) || '-' || RIGHT('00' || CAST(SML291 AS VARCHAR(2)),2) || '-' || RIGHT('00' || CAST(SML292 AS VARCHAR(2)),2) ELSE NULL END AS VARCHAR(10)) as LOAN_MTR_DT, CAST(CASE WHEN LENGTH(SME140) = 7 THEN SUBSTRING(CAST('0' || CAST(SME140 AS VARCHAR(8)) AS VARCHAR(8)),1,2) || '-' || SUBSTRING(CAST('0' || CAST(SME140 AS VARCHAR(8)) AS VARCHAR(8)),3,2) || '-' || SUBSTRING(CAST('0' || CAST(SME140 AS VARCHAR(8)) AS VARCHAR(8)),5,4) WHEN LENGTH(SME140) = 8 THEN SUBSTRING(CAST(SME140 AS VARCHAR(8)),1,2) || '-' || SUBSTRING(CAST(SME140 AS VARCHAR(8)),3,2) || '-' || SUBSTRING(CAST(SME140 AS VARCHAR(8)),5,4) ELSE CAST(NULL AS VARCHAR(8)) END AS VARCHAR(10)) as LAST_ESCRW_ANLS_DT, CAST(CASE WHEN(SML023 = '2' OR SMFL20 = 'A' OR SMFL20 = 'B' OR SMFL20 = 'C' OR SMFL20 = 'I') THEN 'Y' ELSE 'N' END AS CHAR(1)) as ARM_IND, CAST(CASE WHEN ESCE.LOAN_NBR IS NOT NULL THEN 'Y' ELSE 'N' END AS CHAR(1)) as ESCRW_IND, CAST(M132FL AS CHAR(1)) as HGHR_PRC_MTG_LOAN_IND, CAST(SMX030 AS VARCHAR(16)) as LATE_CHRG_CD, CAST(SMX060 AS INTEGER) as LATE_CHRG_GRACE_PRD_DAY_CNT, CAST(SMX020 * 100 AS number(6,3)) as LATE_CHRG_RT_PCT, CAST(SMA491 AS VARCHAR(16)) as INT_METH_CD, CAST(M1P4PL AS INTEGER) as PYMT_APPL_PLN_NBR, CAST(M1PRCD AS CHAR(16)) as PROD_CD, CAST(CFALWPRN AS CHAR(1)) as PRIN_PYMT_ALOW_IND, CAST(CFFEEELG AS CHAR(1)) as TXN_FEE_ELG_CD, CAST(SMM060 AS CHAR(1)) as LATE_CHRG_SRC_CD, CAST(SRVALT2.A2FBT AS NUMERIC(19,4)) as TOT_ANUL_FEE_BILLED_AMT, (CAST(SMR021 AS VARCHAR(3)) || CAST(SMR022 AS VARCHAR(1)) || CAST(SMR023 AS VARCHAR(6)) || CAST(SMR024 AS VARCHAR(1)) || CAST(SMR025 AS VARCHAR(3)) || CAST(SMR026 AS VARCHAR(6))) as FHA_VA_CASE_NBR, CAST(CASE WHEN LENGTH(SRVDSR.SMR027) = 7 THEN SUBSTRING(CAST('0' || CAST(SRVDSR.SMR027 AS VARCHAR(8)) AS VARCHAR(8)),1,2) || '-' || SUBSTRING(CAST('0' || CAST(SRVDSR.SMR027 AS VARCHAR(8)) AS VARCHAR(8)),3,2) || '-' || SUBSTRING(CAST('0' || CAST(SRVDSR.SMR027 AS VARCHAR(8)) AS VARCHAR(8)),5,4) WHEN LENGTH(SRVDSR.SMR027) = 8 THEN SUBSTRING(CAST(SRVDSR.SMR027 AS VARCHAR(8)),1,2) || '-' || SUBSTRING(CAST(SRVDSR.SMR027 AS VARCHAR(8)),3,2) || '-' || SUBSTRING(CAST(SRVDSR.SMR027 AS VARCHAR(8)),5,4) ELSE CAST(NULL AS VARCHAR(8)) END AS VARCHAR(10)) as FHA_CASE_ASGN_DT, CAST(SRVDSR.SMR100 AS CHAR(1)) as MI_PREM_FNCE_IND_CD, CAST(SRVMLD.M1ONSP*100 AS number(6,3)) as MI_PREM_RT_PCT, CAST(LTRIM(RTRIM(SMR051)) || LTRIM(RTRIM(SMR053)) || LTRIM(RTRIM(SMR041)) || LTRIM(RTRIM(SMR042)) AS CHAR(16)) as INVSTR_LOAN_NBR, CAST(CASE WHEN ESC.LOAN_NBR IS NOT NULL THEN 'Y' ELSE 'N' END AS CHAR(1)) as MI_IND, CASE WHEN SRVDSR.SML021 IN('1','2','3','4') THEN CAST(SRVDSR.SML021 AS NA) WHEN SRVDSR.SML021 IS NULL THEN 1 WHEN SRVDSR.SML021 = '0' THEN 0 ELSE 1 END as LIEN_PSTN, CAST(DATEDIFF(DAY,DATEADD(MONTH,-1,CAST(CASE WHEN SMA131 IS NULL OR SMA132 IS NULL OR SMA133 IS NULL OR SMA131 = 0 OR SMA132 = 0 OR SMA133 = 0 THEN NULL WHEN(SMA131 >= 1 AND SMA131 <= 12) AND(SMA132 >= 1 AND SMA132 <= 31) AND(SMA133 >= 1753) THEN CAST(SMA133 AS VARCHAR(4)) || '-' || RIGHT('00' || CAST(SMA131 AS VARCHAR(2)),2) || '-' || RIGHT('00' || CAST(SMA132 AS VARCHAR(2)),2) ELSE NULL END AS DATE)),MONTH) AS NA) as RMN_TERM, CAST(0 AS NUMERIC(6,3)) as CURR_LTV, CAST(0 AS NUMERIC(6,3)) as CURR_CLTV, CAST(SRVMLD.M1OCLT AS NUMERIC(6,3)) as Orig_CLTV, CAST('' AS VARCHAR(60)) as PROD_CD_DESC, CAST(CASE WHEN(SRVMBSP.QDISMO IS NULL OR SRVMBSP.QDISDA IS NULL OR SRVMBSP.QDISYR IS NULL OR SRVMBSP.QDISMO = 0 OR SRVMBSP.QDISDA = 0 OR SRVMBSP.QDISYR = 0) THEN NULL WHEN((SRVMBSP.QDISMO >= 1 AND SRVMBSP.QDISMO <= 12) AND(SRVMBSP.QDISDA >= 1 AND SRVMBSP.QDISDA <= 31) AND(SRVMBSP.QDISYR >= 1753)) THEN CAST(SRVMBSP.QDISYR AS VARCHAR(4)) || '-' || RIGHT('00' || CAST(SRVMBSP.QDISMO AS VARCHAR(2)),2) || '-' || RIGHT('00' || CAST(SRVMBSP.QDISDA AS VARCHAR(2)),2) ELSE NULL END AS VARCHAR(10)) as SECURITIZED_DT, SRVDSR.SME010 as ESCRW_ORGNL_PYMT, CAST(COALESCE(LSBORR001.PAPERLESS_STMT_IND,'N') AS CHAR(1)) as PAPERLESS_STMT_IND, CAST(NULL AS CHAR(2)) as MIN_HZRD_RT_RQR, CAST(SRVDSR.SME060 AS number(13,2)) as ESCRW_ADVN_BY_INVSTR, CASE WHEN(SML113 IS NULL OR SML111 IS NULL OR SML112 IS NULL OR LTRIM(RTRIM(SML111)) = '' OR LTRIM(RTRIM(SML112)) = '' OR LTRIM(RTRIM(SML113)) = '' OR SML111 = '00' OR SML112 = '00' OR SML113 = '0000') THEN CAST(NULL AS DATE) ELSE TO_DATE(TO_VARCHAR(SML113 || RIGHT('00' || LTRIM(RTRIM(SML111)),2) || RIGHT('00' || LTRIM(RTRIM(SML112)),2),'YYYYMMDD')) END as FRST_PYMT_DUE_DT, CAST((CASE WHEN SRVDSR.SML023 = '9' THEN 'Y' ELSE 'N' END) AS CHAR(1)) as BLN_IND, CAST((CASE WHEN SRVMLD.M1IOPO = 'I' THEN 'Y' ELSE 'N' END) AS CHAR(1)) as INT_ONLY_IND, CAST(NULL AS VARCHAR(256)) as MSA_TXT, CAST(SRVDSR.SML024 AS CHAR(1)) as LOAN_ACQ_METH_CD, CAST(((-1) *(DATEDIFF(DAY,CURRENT_TIMESTAMP(),MONTH)) || 1) AS INTEGER) as LOAN_AGE, CAST((-1) * DATEDIFF(DAY,(CASE WHEN(SRVDSR.SML293 IS NULL OR SRVDSR.SML291 IS NULL OR SRVDSR.SML292 IS NULL OR SRVDSR.SML291 = 0 OR SRVDSR.SML292 = 0 OR SRVDSR.SML293 = 0) THEN CAST(NULL AS DATE) WHEN(SRVDSR.SML293 < 1753 OR(SRVDSR.SML291 < 1 OR SRVDSR.SML291 > 12) OR(SRVDSR.SML292 < 1 OR SRVDSR.SML292 > 31)) THEN CAST(NULL AS DATE) ELSE CAST(CAST(SRVDSR.SML293 AS VARCHAR(4)) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SML291)),2) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SML292)),2) AS DATE) END),MONTH) || 1 AS INTEGER) as AMZ_TERM, CAST(COALESCE(SRVDSR.SMX051/10000,0) AS number(10,5)) as GRT_FEE, CASE WHEN SRVDSR.SMA240 = 0.00 THEN CAST(NULL AS DATE) WHEN(SRVDSR.SMA123 IS NULL OR SRVDSR.SMA121 IS NULL OR SRVDSR.SMA122 IS NULL OR SRVDSR.SMA123 = 0 OR SRVDSR.SMA121 = 0 OR SRVDSR.SMA122 = 0) THEN CAST(NULL AS DATE) ELSE CAST(CAST(SRVDSR.SMA123 AS VARCHAR(4)) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SMA121)),2) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SMA122)),2) AS DATE) END as LAST_ACTV_DT, CASE WHEN(SRVDSR.SMA143 IS NULL OR SRVDSR.SMA141 IS NULL OR SRVDSR.SMA142 IS NULL OR SRVDSR.SMA143 = 0 OR SRVDSR.SMA141 = 0 OR SRVDSR.SMA142 = 0) THEN CAST(NULL AS DATE) ELSE CAST(CAST(SRVDSR.SMA143 AS VARCHAR(4)) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SMA141)),2) || '-' || RIGHT('00' || LTRIM(RTRIM(SRVDSR.SMA142)),2) AS DATE) END as LAST_DUE_DT, CAST(SRVDSR.SMM010 AS CHAR(2)) as LSAMS_RFD_CD, CAST(SRVDSR.SML023 AS CHAR(1)) as MTG_INSMT, CAST(SRVDSR.SML022 AS CHAR(1)) as MTG_TYPE, CAST(CASE WHEN DATEDIFF(DAY,CURRENT_TIMESTAMP(),MONTH) > 0 THEN 0 ELSE DATEDIFF(DAY,CURRENT_TIMESTAMP(),MONTH) END AS INTEGER) *(-1) as MTH_PAST_DUE, CAST(SRVDSR.SMA170 AS number(4,2)) as NON_SFCNT_FUND_CHRG_AMT, CAST(CASE WHEN SRVDSR.SMX052 = 'S' THEN ROUND(SRVDSR.SMX041/1000000,7) || ROUND(SRVDSR.SMX100/100000,7) ELSE ROUND(SRVDSR.SMX041/1000000,7) || ROUND(SRVDSR.SMX051/1000000,7) || ROUND(SRVDSR.SMX100/100000,7) END AS number(8,7)) as SRVC_FEE_AMT, CAST(SRVDSR.SME310 AS number(5,2)) as YR_TO_DT_WHLD, (CASE WHEN COALESCE(SRVDSR.SMFL5,'0') = '0' THEN 0 ELSE CAST(DATEDIFF(DAY,CAST(CASE WHEN LENGTH(COALESCE(SRVDSR.SMFL5,0))  !=  8 THEN NULL ELSE LEFT(SRVDSR.SMFL5,4) || '-' || SUBSTRING(CAST(SRVDSR.SMFL5 AS VARCHAR(8)),5,2) || '-' || RIGHT(SRVDSR.SMFL5,2) END AS DATE),MONTH) AS INTEGER) END) *(-1) as INT_ONLY_TERM, CAST(CASE WHEN LTRIM(RTRIM(LSLOAN00.LSSTPADV)) = 'Y' THEN 'Y' WHEN LTRIM(RTRIM(LSLOAN00.LSSTPADV)) = 'N' THEN 'N' WHEN LTRIM(RTRIM(LSLOAN00.LSSTPADV)) = '' THEN '' ELSE LSLOAN00.LSSTPADV END AS CHAR(1)) as STOP_ADVN_FLG, CAST((SRVBAL.BLCABL* -1) || SRVBAL.SMA422 || CASE WHEN SRVDSR.SME050 IS NULL THEN 0 ELSE SRVDSR.SME050 END AS number(19,4)) as TOT_ADVN_BAL_AMT, CAST(SRVDSR.SMM030 AS CHAR(2)) as SMM030, CAST(SRVDSR.SMM040 AS CHAR(2)) as SMM040, CAST(SRVDSR.SMM050 AS CHAR(2)) as SMM050, CAST(SRVDSR.SMR110 AS number(7,0)) as SMR110, CAST(SRVDSR.SMR070 AS CHAR(3)) as SMR070, CAST(SRVDSR.SMM090 AS CHAR(1)) as SMM090, CAST(SRVMLD.SMA300 AS number(5,0)) as SMA300, CAST(LSLOAN00.LSTAXWIOPT AS CHAR(1)) as WI_TAX_OPT, CAST(SRVDSR.SML280 AS CHAR(1)) as FLOOD_INS_RQR_FLG, CAST(LTRIM(RTRIM(SRVMBSP2.G2GPOOL)) AS VARCHAR(8)) as INVSTR_POOL_NBR, CAST(SML270 AS number(5,2)) as MI_PCT_CVR_AMT, CAST(SRVMLD.M1MINN AS CHAR(18)) as MIN_MERS_NBR, CAST(SRVMLD.M1REGM AS CHAR(1)) as RGST_WITH_MERS_FLG, CAST('ETL-Insert' AS VARCHAR(50)) as AUD_CRE_BY_NM, CURRENT_TIMESTAMP as AUD_CRE_DTTM, CAST('ETL-Update' AS VARCHAR(50)) as AUD_UPD_BY_NM, CURRENT_TIMESTAMP as AUD_UPD_DTTM, CAST('#TRUNC_FLAG#' AS CHAR(1)) as TRUNCATE_FLAG, CAST(SRVMLD.M1LTIN AS CHAR(1)) as LOAN_TYPE_IND, CAST(LTRIM(RTRIM(SRVMLD.SMP050)) AS VARCHAR(9)) as PROP_ZIP, CAST(CASE WHEN LTRIM(RTRIM(COALESCE(M1NEGA,''))) = 'Y' THEN '1' ELSE '0' END AS CHAR(1)) as NEG_AMZ_IND, A2CAPV as LAST_APPR_VAL, SMP200 as ORIG_APPR_VAL, a2sprc as SAL_PR, CAST(CASE WHEN SRVDSR.SML010 IN(SELECT CNSMR_LOAN_CD FROM CNSMR_LOAN_CHK) THEN 'Y' ELSE 'N' END AS CHAR(1)) as CNSMR_LOAN_FLG FROM {{ source('SS_SRC_SERVICING_DB','ADMIN') }}.#SS_SRC_SRVDSR_TBL# as SRVDSR JOIN {{ source('ADMIN','LSLOAN00') }} ON U_LOAN_NUM_N= LSLN_N LEFT JOIN {{ source('ADMIN','BRANDFLP') }} as BDFLP ON SRVDSR.U_LOAN_NUM_N= BDFLP.LOAN LEFT JOIN {{ source('ADMIN','SRVMLD') }} ON U_LOAN_NUM= M1LOAN LEFT JOIN {{ source('ADMIN','SRVALT2') }} ON U_LOAN_NUM_N= A2LOAN LEFT JOIN (SELECT distinct LOAN_NBR, LOAD_DTTM FROM {{ source('ADMIN','SRVESCE') }} WHERE ESCROW_TYPE IN('40','70','71','74')) ESC ON U_LOAN_NUM_N= ESC.LOAN_NBR LEFT JOIN (SELECT distinct LOAN_NBR FROM {{ source('ADMIN','SRVESCE') }} WHERE ANALYSIS_YN_FLAG IN('Y')) ESCE ON U_LOAN_NUM= ESCE.LOAN_NBR LEFT JOIN {{ source('ADMIN','SRVMBSP') }} ON SRVMBSP.POOL= SRVDSR.SMR110 AND SRVDSR.SMR070= SRVMBSP.INVSTR LEFT JOIN {{ source('ADMIN','SRVMBSP2') }} ON SRVMBSP2.G2INV= SRVDSR.SMR070 AND LTRIM(RTRIM(SRVDSR.SMR110))= LTRIM(RTRIM(SRVMBSP2.G2LPOOL)) LEFT JOIN (SELECT TEMP1.LBLN_N, TEMP1.PAPERLESS_STMT_IND as PAPERLESS_STMT_IND, LSBORR00.LOAD_DTTM as LOAD_DTTM FROM {{ source('ADMIN','LSBORR00') }} JOIN (SELECT A.LBLN_N, CASE WHEN A.PAPERLESS_STMT_IND = '1' THEN 'Y' ELSE 'N' END as PAPERLESS_STMT_IND FROM (SELECT MAX(CASE WHEN COALESCE(LTRIM(RTRIM(LBEBILFGB)),'0') IN('','0','A','X','C','D','B','N','Y') THEN '0' ELSE LTRIM(RTRIM(LBEBILFGB)) END) as PAPERLESS_STMT_IND, LBLN_N FROM {{ source('ADMIN','LSBORR00') }} GROUP BY LBLN_N) A) TEMP1 ON LSBORR00.LBLN_N= TEMP1.LBLN_N) LSBORR001 ON SRVDSR.U_LOAN_NUM_N= LSBORR001.LBLN_N LEFT JOIN {{ source('ADMIN','SRVBAL') }} ON U_LOAN_NUM_N= SRVBAL.BLLOAN WHERE CASE 'DSHASHDISPATCH_FLAGDSHASH' WHEN 'N' THEN 0 ELSE CASE 'DSHASHTRUNC_FLAGDSHASH' WHEN 'Y' THEN 1 ELSE CASE WHEN SRVDSR.LOAD_DTTM > 'DSHASHSRVDSR_LOADDTTMDSHASH' OR SRVMLD.LOAD_DTTM > 'DSHASHSRVMLD_LOADDTTMDSHASH' OR SRVALT2.LOAD_DTTM > 'DSHASHSRVALT2_LOADDTTMDSHASH' OR ESC.LOAD_DTTM > 'DSHASHSRVESCE_LOADDTTMDSHASH' OR LSBORR001.LOAD_DTTM > 'DSHASHLSBORR00_LOADDTTMDSHASH' OR SRVMBSP.LOAD_DTTM > 'DSHASHSRVMBSP_LOADDTTMDSHASH' OR SRVMBSP2.LOAD_DTTM > 'DSHASHSRVMBSP2_LOADDTTMDSHASH' OR BDFLP.CREATEDTS > 'DSHASHBDFL_CREATDTSDSHASH' OR BDFLP.UPDATEDTS > 'DSHASHBDFL_UPDATDTSDSHASH' THEN 1 ELSE 0 END END END= 1)
 ),

