XFM_LOANOut as (
	
Select 
LOAN_KEY as LOAN_KEY,
BRND_NM as BRND_NM,
TRIM ( LOAN_TYPE_CD ) as LOAN_TYPE_CD,
TRIM ( LOAN_STS_CD ) as LOAN_STS_CD,
TRIM ( INVSTR_CD ) as INVSTR_CD,
TRIM ( POOL_ID ) as POOL_ID,
NOTE_RT_PCT as NOTE_RT_PCT,
NOTE_AMT as NOTE_AMT,
UPB_AMT as UPB_AMT,
ESCRW_ADVN_AMT as ESCRW_ADVN_AMT,
ESCRW_BAL_AMT as ESCRW_BAL_AMT,
ESCRW_BAL_UNENCB_AMT as ESCRW_BAL_UNENCB_AMT,
MTH_LATE_CHRG_AMT as MTH_LATE_CHRG_AMT,
TO_DATE ( LAST_PYMT_RCV_DT,
"%yyyy-%mm-%dd" ) as LAST_PYMT_RCV_DT,
TO_DATE ( NXT_PYMT_DUE_DT,
"%yyyy-%mm-%dd" ) as NXT_PYMT_DUE_DT,
TO_DATE ( LOAN_MTR_DT,
"%yyyy-%mm-%dd" ) as LOAN_MTR_DT,
CASE WHEN LAST_ESCRW_ANLS_DT IS NULL THEN Null ds ELSE ( CASE WHEN TRY_TO_NUMBER ( "date",
LAST_ESCRW_ANLS_DT,
"%mm-%dd-%yyyy" ) IS NOT NULL THEN TO_DATE ( LAST_ESCRW_ANLS_DT,
"%mm-%dd-%yyyy" ) ELSE Null END ) END as LAST_ESCRW_ANLS_DT,
ARM_IND as ARM_IND,
ESCRW_IND as ESCRW_IND,
HGHR_PRC_MTG_LOAN_IND as HGHR_PRC_MTG_LOAN_IND,
TRIM ( LATE_CHRG_CD ) as LATE_CHRG_CD,
LATE_CHRG_GRACE_PRD_DAY_CNT as LATE_CHRG_GRACE_PRD_DAY_CNT,
LATE_CHRG_RT_PCT as LATE_CHRG_RT_PCT,
TRIM ( INT_METH_CD ) as INT_METH_CD,
PYMT_APPL_PLN_NBR as PYMT_APPL_PLN_NBR,
TRIM ( PROD_CD ) as PROD_CD,
LATE_CHRG_SRC_CD as LATE_CHRG_SRC_CD,
TOT_ANUL_FEE_BILLED_AMT as TOT_ANUL_FEE_BILLED_AMT,
TRIM ( FHA_VA_CASE_NBR ) as FHA_VA_CASE_NBR,
CASE WHEN FHA_CASE_ASGN_DT IS NULL THEN Null ds ELSE ( CASE WHEN TRY_TO_NUMBER ( "date",
FHA_CASE_ASGN_DT,
"%mm-%dd-%yyyy" ) IS NOT NULL THEN TO_DATE ( FHA_CASE_ASGN_DT,
"%mm-%dd-%yyyy" ) ELSE Null END ) END as FHA_CASE_ASGN_DT,
MI_PREM_FNCE_IND_CD as MI_PREM_FNCE_IND_CD,
MI_PREM_RT_PCT as MI_PREM_RT_PCT,
TRIM ( INVSTR_LOAN_NBR ) as INVSTR_LOAN_NBR,
MI_IND as MI_IND,
LIEN_PSTN as LIEN_PSTN,
RMN_TERM as RMN_TERM,
CURR_LTV as CURR_LTV,
CURR_CLTV as CURR_CLTV,
Orig_CLTV as Orig_CLTV,
TRIM ( PROD_CD_DESC ) as PROD_CD_DESC,
TO_DATE ( SECURITIZED_DT,
"%yyyy-%mm-%dd" ) as SECURITIZED_DT,
ESCRW_ORGNL_PYMT as ESCRW_ORGNL_PYMT,
PAPERLESS_STMT_IND as PAPERLESS_STMT_IND,
MIN_HZRD_RT_RQR as MIN_HZRD_RT_RQR,
ESCRW_ADVN_BY_INVSTR as ESCRW_ADVN_BY_INVSTR,
FRST_PYMT_DUE_DT as FRST_PYMT_DUE_DT,
BLN_IND as BLN_IND,
INT_ONLY_IND as INT_ONLY_IND,
MSA_TXT as MSA_TXT,
LOAN_ACQ_METH_CD as LOAN_ACQ_METH_CD,
LOAN_AGE as LOAN_AGE,
AMZ_TERM as AMZ_TERM,
GRT_FEE as GRT_FEE,
LAST_ACTV_DT as LAST_ACTV_DT,
LAST_DUE_DT as LAST_DUE_DT,
LSAMS_RFD_CD as LSAMS_RFD_CD,
MTG_TYPE as MTG_TYPE,
MTG_INSMT as MTG_INSMT,
MTH_PAST_DUE as MTH_PAST_DUE,
NON_SFCNT_FUND_CHRG_AMT as NON_SFCNT_FUND_CHRG_AMT,
SRVC_FEE_AMT as SRVC_FEE_AMT,
YR_TO_DT_WHLD as YR_TO_DT_WHLD,
INT_ONLY_TERM as INT_ONLY_TERM,
STOP_ADVN_FLG as STOP_ADVN_FLG,
WI_TAX_OPT as WI_TAX_OPT,
AUD_CRE_BY_NM as AUD_CRE_BY_NM,
