INVSTR_POOL_NBR as INVSTR_POOL_NBR,
MI_PCT_CVR_AMT as MI_PCT_CVR_AMT,
AUD_CRE_DTTM as AUD_CRE_DTTM,
'LSM' as SOR_CD,
LOAN_NBR || '~' || 'LSM' || '~' || TRIM ( CASE WHEN BRND_NM is null THEN '<NULL>' ELSE BRND_NM END ) as UNQ_KEY_TXT,
AUD_UPD_BY_NM as AUD_UPD_BY_NM,
AUD_UPD_DTTM as AUD_UPD_DTTM,
TRUNCATE_FLAG as TRUNCATE_FLAG,
LOAN_TYPE_IND as LOAN_TYPE_IND,
MIN_MERS_NBR as MIN_MERS_NBR,
RGST_WITH_MERS_FLG as RGST_WITH_MERS_FLG,
NEG_AMZ_IND as NEG_AMZ_IND,
CNSMR_LOAN_FLG as CNSMR_LOAN_FLG
From JN_LOAN_KEYOut as JN_LOAN_KEYOut),

JNR_MSG_CDOut as (
Select 
	LKP_BKPT_CASE_TRKOut.LOAN_KEY as LOAN_KEY,
	 LKP_BKPT_CASE_TRKOut.SMR070 as SMR070,
	 SS_SRC_LOAN_MSG_CDOut.MSG_SQ_NBR as MSG_SQ_NBR,
	 LKP_BKPT_CASE_TRKOut.LOAN_TYPE_CD as LOAN_TYPE_CD,
	 LKP_BKPT_CASE_TRKOut.SMA300 as SMA300,
	 SS_SRC_LOAN_MSG_CDOut.LOAN_KEY as LOAN_KEY,
	 LKP_BKPT_CASE_TRKOut.SMR110 as SMR110,
	 LKP_BKPT_CASE_TRKOut.SMM090 as SMM090,
	 LKP_BKPT_CASE_TRKOut.KEY1 as KEY1,
	 LKP_BKPT_CASE_TRKOut.LIEN_PSTN as LIEN_PSTN,
	 LKP_BKPT_CASE_TRKOut.FILE_CHAP_CD as FILE_CHAP_CD,
	 SS_SRC_LOAN_MSG_CDOut.MSG_CD as MSG_CD 
From
SS_SRC_LOAN_MSG_CDOut as SS_SRC_LOAN_MSG_CDOut left JOIN SS_SRC_LOAN_MSG_CDOut as SS_SRC_LOAN_MSG_CDOut 
ON
SS_SRC_LOAN_MSG_CDOut.LOAN_KEY = LKP_BKPT_CASE_TRKOut.LOAN_KEY 
),

XFM_MSG_CDOut as (
	
Select 
CASE WHEN MSG_CD IS NULL THEN 'ZZ' ELSE MSG_CD END as svMSGCD,
CASE WHEN TRIM ( svMSGCD ) = '08' THEN 'Y' ELSE 'N' END as svACTVFRCLSIND,
CASE WHEN KEY1 IS NULL THEN 'N' ELSE 'Y' END as svBKPTIND,
CASE WHEN TRIM ( svMSGCD ) = '06' THEN 'Y' ELSE 'N' END as svREOIND,
CASE WHEN TRIM ( svMSGCD ) = '17' OR TRIM ( svMSGCD ) = '27' OR TRIM ( svMSGCD ) = '43' THEN 'Y' ELSE 'N' END as svDSCHRGBKPTIND,
CASE WHEN TRIM ( svMSGCD ) = '06' OR TRIM ( svMSGCD ) = '85' OR TRIM ( svMSGCD ) = '49' OR SMR110 = 3 OR TRIM ( SMR070 ) = '995' OR TRIM ( SMM090 ) = 'F' OR TRIM ( svMSGCD ) = '91' OR TRIM ( svMSGCD ) = '90' OR ( ( LOAN_TYPE_CD = '30' ) AND ( LIEN_PSTN = 2 ) ) THEN 'N' ELSE 'Y' END as svMSGCDWEBSITEACCSALOWIND,
CASE WHEN svBKPTIND = 'Y' AND ( FILE_CHAP_CD = '07' OR FILE_CHAP_CD = '11' OR FILE_CHAP_CD = '12' OR FILE_CHAP_CD = '13' ) THEN 'Y' ds ELSE ( CASE WHEN svBKPTIND = 'N' THEN 'Y' ELSE 'N' END ) END as svBKPTWEBSITEACCSALOWIND,
CASE WHEN svMSGCDWEBSITEACCSALOWIND = 'Y' AND svBKPTWEBSITEACCSALOWIND = 'Y' ) OR SMR110 = 3 THEN 'Y' ELSE 'N' END as svWEBSITEACCSALOWIND,
LOAN_KEY as LOAN_KEY,
svACTVFRCLSIND as ACTV_FRCLS_IND,
svBKPTIND as BKPT_IND,
svREOIND as REO_IND,
svDSCHRGBKPTIND as DSCHRG_BKPT_IND,
svWEBSITEACCSALOWIND as WEBSITE_ACCS_ALOW_IND
From JNR_MSG_CDOut as JNR_MSG_CDOut),

AGG_LOAN_KEY_Out as (
	 
 select 
	lnk_agg.LOAN_KEY as LOAN_KEY,
	 MAX ( lnk_agg.ACTV_FRCLS_IND ) as ACTV_FRCLS_IND,
	 MAX ( lnk_agg.BKPT_IND ) as BKPT_IND,
	 MAX ( lnk_agg.DSCHRG_BKPT_IND ) as DSCHRG_BKPT_IND,
	 MAX ( lnk_agg.REO_IND ) as REO_IND,
	 MIN ( lnk_agg.WEBSITE_ACCS_ALOW_IND ) as WEBSITE_ACCS_ALOW_IND
 from XFM_MSG_CDOut
 group by LOAN_KEY
)
),

Copy_58Out as (
	
Select 
LOAN_KEY as LOAN_KEY,
ACTV_FRCLS_IND as ACTV_FRCLS_IND,
BKPT_IND as BKPT_IND,
